const run = $('Run persistent TED monitoring Task').first().json;
const rows = $input.all()
  .map((item) => item.json)
  .filter((row) => row && Object.keys(row).length > 0);

if (rows.length === 0) {
  return [{ json: { hasRecord: false, exposeTender: false, runId: run.id, runStatus: run.status, datasetId: run.defaultDatasetId } }];
}

return rows.map((record, index) => {
  const isTender = record.recordType === 'tender';
  const hasPublicationNumber = typeof record.publicationNumber === 'string' && record.publicationNumber.length > 0;
  const deliveryKey = isTender && hasPublicationNumber
    ? `ted:${record.publicationNumber}`
    : `ted:run:${run.id}:row:${index}`;
  const displayTitle = typeof record.title === 'string' && record.title.trim().length > 0
    ? record.title
    : hasPublicationNumber ? `Tender ${record.publicationNumber}` : `TED ${record.recordType ?? 'dataset'} record`;
  const normalized = isTender && hasPublicationNumber ? {
    publicationNumber: record.publicationNumber,
    publicationDate: record.publicationDate ?? null,
    noticeType: record.noticeType ?? null,
    isChangeNotice: record.isChangeNotice === true,
    modifiesPublicationNumber: record.modifiesPublicationNumber ?? null,
    title: record.title ?? null,
    displayTitle,
    buyerName: record.buyerName ?? null,
    buyerCountry: record.buyerCountry ?? null,
    cpvCodes: record.cpvCodes ?? [],
    estimatedValueEur: record.estimatedValueEur ?? null,
    valueUnknown: record.valueUnknown === true,
    deadlineDate: record.deadlineDate ?? null,
    links: record.links ?? { html: null, pdf: null, xml: null },
    firstSeenAt: record.firstSeenAt ?? null,
  } : null;

  return { json: {
    hasRecord: true,
    exposeTender: normalized !== null,
    deliveryKey,
    product: 'ted',
    sourceId: hasPublicationNumber ? record.publicationNumber : `run:${run.id}:row:${index}`,
    sourceUrl: record.links?.html ?? '',
    title: displayTitle,
    observedAt: record.firstSeenAt ?? record.completedAt ?? null,
    runId: run.id,
    runStatus: run.status,
    datasetId: run.defaultDatasetId,
    payloadJson: JSON.stringify(record),
    normalized,
  } };
});

const run = $('Run persistent TED monitoring Task').first().json;
const prepared = $('Prepare every dataset record').all();
const records = prepared.filter((item) => item.json.hasRecord === true);
const tenders = records.filter((item) => item.json.exposeTender === true).map((item) => item.json.normalized);
const result = {
  runId: run.id,
  status: run.status,
  defaultDatasetId: run.defaultDatasetId ?? null,
  datasetRecordCount: records.length,
  recordsPersisted: records.length,
  tenderCount: tenders.length,
  tenders,
  terminalFailure: run.status !== 'SUCCEEDED',
};

if (run.status !== 'SUCCEEDED') {
  throw new Error(`Apify Task run ${run.id} finished ${run.status} after ${records.length} committed dataset record(s) were idempotently persisted`);
}

return [{ json: result }];

const run = $('Run persistent TED monitoring Task').first().json;
const result = { runId: run.id, status: run.status, defaultDatasetId: null, datasetRecordCount: 0, recordsPersisted: 0, tenderCount: 0, tenders: [], terminalFailure: run.status !== 'SUCCEEDED', diagnostic: 'Terminal run has no defaultDatasetId; no dataset request was attempted.' };
if (run.status !== 'SUCCEEDED') throw new Error(`Apify Task run ${run.id} finished ${run.status} without a defaultDatasetId; no records were available to ingest`);
return [{ json: result }];
